INSERT INTO pain_library (pain_id, persona, pain_statement, primary_module, benefit_driver, benefit_type, default_kpi, default_value_es, default_value_fr, display_order) VALUES ('P01', 'HR Director', 'No real-time visibility into headcount, org structure, or basic employee data; data is scattered across spreadsheets and emails.', 'Core', 'time saved on org-chart maintenance + reporting', 'time_saved', 'HR ops hours/week saved running reports', 3.0, 3.0, 1);
INSERT INTO pain_library (pain_id, persona, pain_statement, primary_module, benefit_driver, benefit_type, default_kpi, default_value_es, default_value_fr, display_order) VALUES ('P02', 'HR Director', 'Time-off accrual rules and country-specific holidays are managed manually, creating compliance and dispute risk.', 'Time Off', 'admin time saved + dispute/compliance risk avoided', 'time_saved + risk_reduction', 'hours/week saved + €/year of dispute exposure avoided', 4.0, 5.0, 2);
INSERT INTO pain_library (pain_id, persona, pain_statement, primary_module, benefit_driver, benefit_type, default_kpi, default_value_es, default_value_fr, display_order) VALUES ('P03', 'HR Director', 'Talent attrition is high; we can''t identify disengaged employees before they leave; replacement costs are silently eating margin.', 'Performance + Engagement', 'attrition reduction', 'retention_uplift', 'percentage-point reduction in attrition × replacement cost', 15000.0, 22000.0, 3);
INSERT INTO pain_library (pain_id, persona, pain_statement, primary_module, benefit_driver, benefit_type, default_kpi, default_value_es, default_value_fr, display_order) VALUES ('P04', 'HR Director', 'Onboarding new hires takes too long, paperwork is everywhere, time-to-productivity is slow.', 'Core + Trainings', 'time-to-productivity improvement + admin time saved', 'onboarding_acceleration', 'days saved per new hire × loaded daily cost × hires/year', 250.0, 320.0, 4);
INSERT INTO pain_library (pain_id, persona, pain_statement, primary_module, benefit_driver, benefit_type, default_kpi, default_value_es, default_value_fr, display_order) VALUES ('P05', 'People Ops', 'Time tracking is manual/paper or excel; we struggle with EU labour-law compliance (ES Real Decreto / FR weekly reporting); audit risk is real.', 'Time Tracking', 'admin time saved + compliance fine risk avoided', 'time_saved + risk_reduction', 'minutes/employee/day × employees × work days + annual fine exposure', 15.0, 15.0, 5);
INSERT INTO pain_library (pain_id, persona, pain_statement, primary_module, benefit_driver, benefit_type, default_kpi, default_value_es, default_value_fr, display_order) VALUES ('P06', 'People Ops', 'Shift planning / scheduling is done in spreadsheets; over- and under-staffing causes payroll waste and customer-experience issues.', 'Time Planning', 'overstaffing waste reduction + planning time saved', 'workforce_optimization', '% over/under-staffing reduction × payroll volume', 3.0, 3.0, 6);
INSERT INTO pain_library (pain_id, persona, pain_statement, primary_module, benefit_driver, benefit_type, default_kpi, default_value_es, default_value_fr, display_order) VALUES ('P07', 'People Ops', 'We can''t fill open roles fast enough; agency fees are killing budget; time-to-hire too long.', 'Recruitment', 'agency fee avoidance + time-to-hire reduction', 'agency_fee_avoidance', '% hires sourced internally × agency fee × annual hires', 4500.0, 6500.0, 7);
INSERT INTO pain_library (pain_id, persona, pain_statement, primary_module, benefit_driver, benefit_type, default_kpi, default_value_es, default_value_fr, display_order) VALUES ('P08', 'People Ops', 'Training compliance and L&D is fragmented; we can''t prove training delivery for FUNDAE/audits or for ISO/quality certs.', 'Trainings + LMS', 'admin time saved + training subsidy capture', 'training_subsidy_recapture', 'FUNDAE/CPF subsidy not currently claimed + admin hours', 30.0, 40.0, 8);
INSERT INTO pain_library (pain_id, persona, pain_statement, primary_module, benefit_driver, benefit_type, default_kpi, default_value_es, default_value_fr, display_order) VALUES ('P09', 'Finance', 'Expense reporting takes finance days to close each month; receipts go missing; reconciliation is painful.', 'Expenses', 'finance hours saved + leakage avoidance', 'time_saved + leakage_reduction', 'minutes/expense × expenses/employee/month × employees × 12', 5.0, 5.0, 9);
INSERT INTO pain_library (pain_id, persona, pain_statement, primary_module, benefit_driver, benefit_type, default_kpi, default_value_es, default_value_fr, display_order) VALUES ('P10', 'Finance', 'Procurement and vendor spend is uncontrolled; maverick spend is high; we can''t enforce approvals.', 'Procurement', 'procurement leakage reduction', 'leakage_reduction', '% maverick spend captured × annual procurable spend', 0.04, 0.04, 10);
INSERT INTO pain_library (pain_id, persona, pain_statement, primary_module, benefit_driver, benefit_type, default_kpi, default_value_es, default_value_fr, display_order) VALUES ('P11', 'Finance', 'Payroll runs require manual reconciliation; error rate is unacceptable; finance and HR re-key the same data.', 'Compensation + Payroll Connect / SILAE', 'payroll error reduction + double-entry elimination', 'time_saved + error_reduction', 'hours/payroll × payrolls/year + cost per error × errors avoided', 120.0, 180.0, 11);
INSERT INTO pain_library (pain_id, persona, pain_statement, primary_module, benefit_driver, benefit_type, default_kpi, default_value_es, default_value_fr, display_order) VALUES ('P12', 'IT/Admin', 'We don''t know what software each employee has; license waste is high; offboarding is a security risk because of orphan accounts.', 'Software Management + IT Inventory', 'license waste + security incident avoidance', 'license_waste_reduction', '% unused licenses identified × avg license cost × employees', 120.0, 150.0, 12);